from pydantic_ai import Agent, RunContext

@dataclass
class UserDeps:
    username: str
    tier: str   # "free" | "pro"

agent = Agent(model="openai:gpt-4o-mini", deps_type=UserDeps)

@agent.system_prompt
def personalised_prompt(ctx: RunContext[UserDeps]) -> str:
    return (
        f"You are a helpful assistant for {ctx.deps.username}. "
        f"They are on the {ctx.deps.tier} plan. "
        + ("Be concise." if ctx.deps.tier == "free" else "Provide detailed explanations.")
    )

result = agent.run_sync(
    "Explain async/await in Python.",
    deps=UserDeps(username="Alice", tier="pro"),
)

from pydantic import BaseModel
from pydantic_ai import Agent, RunContext
from pydantic_ai.exceptions import ModelRetry

class SentimentResult(BaseModel):
    sentiment: str   # "positive", "neutral", or "negative"
    confidence: float

agent = Agent(
    model="openai:gpt-4o-mini",
    result_type=SentimentResult,
    system_prompt="Classify the sentiment of the given text.",
)

@agent.result_validator
def validate_sentiment(ctx: RunContext, result: SentimentResult) -> SentimentResult:
    if result.sentiment not in ("positive", "neutral", "negative"):
        raise ModelRetry(
            f"Invalid sentiment '{result.sentiment}'. "
            "Must be 'positive', 'neutral', or 'negative'."
        )
    if not (0.0 <= result.confidence <= 1.0):
        raise ModelRetry("confidence must be between 0.0 and 1.0")
    return result

result = agent.run_sync("I absolutely love this product!")
print(result.data)   # SentimentResult(sentiment='positive', confidence=0.98)
